(function () {
    let mediaRecorder;
    let audioChunks = [];
    let audioContext, analyser, source;
    let recordingStarted = false;
    let silenceTimer = null;
    let recordingMaxTimer = null;
    let recordingSaved = false;
    let isUploading = false;
    let isHandlingUpload = false;
    let speechFrameCount = 0;
    let nonSpeechFrameCount = 0;
    let adaptiveNoiseFloor = 0.006;
    let speechConfidence = 0;
    let vadCalibrating = true;
    let vadCalibrationFrames = 0;
    let transientSuppressionFramesLeft = 0;

    const vadConfig = {
        frameIntervalMs: 100,
        minSpeechFramesToStart: 3,
        nonSpeechFramesToStop: 20,
        calibrationFrameCount: 3,
        energyThresholdRatio: 1.75,
        minRmsEnergy: 0.01,
        minStartRmsEnergy: 0.01,
        speechBandMinHz: 85,
        speechBandMaxHz: 3800,
        speechBandRatioThreshold: 0.35,
        minZeroCrossingRate: 0.006,
        maxZeroCrossingRate: 0.24,
        noiseFloorSmoothing: 0.96,
        speechConfidenceStartThreshold: 0.52,
        speechConfidenceKeepThreshold: 0.42,
        confidenceRise: 0.2,
        confidenceFall: 0.12,
        pitchMinHz: 85,
        pitchMaxHz: 300,
        voicedCorrelationThreshold: 0.34,
        unvoicedSpeechBandBoost: 0.1,
        transientEnergySpikeRatio: 2.6,
        transientMaxSpeechBandRatio: 0.32,
        transientMinZeroCrossingRate: 0.07,
        transientSuppressionFrames: 6,
        transientMinCrestFactor: 16,
        // Reject whistles / high tones (periodicity above normal human F0)
        highPitchDetectMinHz: 400,
        highPitchDetectMaxHz: 4000,
        highPitchCorrelationThreshold: 0.28,
        // Unvoiced speech still has meaningful energy in low band (~80–1200 Hz)
        unvoicedLowBandMinHz: 80,
        unvoicedLowBandMaxHz: 1200,
        minLowBandRatioForUnvoiced: 0.14,
        // Shrill / treble-heavy noise (fraction of spectrum above this Hz)
        highFreqCutoffHz: 2200,
        maxHighFreqEnergyRatioForUnvoiced: 0.45,
        // Mouse clicks: very spiky waveform (peak >> RMS)
        maxCrestFactorForUnvoiced: 21,
        // Narrowband whistle: dominant bin vs average in speech band (high = pure tone)
        maxSpeechBandPeakinessForUnvoiced: 14
    };

    const dbName = 'audioRecordingsDB';
    const storeName = 'audioChunks';
    const INDEXEDDB_OWNER_KEY = 'quizproctoring_audio_indexeddb_owner';
    let db;

    function parseQuizIdForAudio() {
        const raw = localStorage.getItem('quizid');
        if (raw === null || raw === '') {
            return '';
        }
        try {
            const parsed = JSON.parse(raw);
            return parsed != null ? String(parsed) : '';
        } catch (err) {
            return raw;
        }
    }

    function getAudioAttemptOwnerKey() {
        const quizid = parseQuizIdForAudio();
        const attemptInput = document.querySelector('input[name="attempt"]');
        const attemptid = attemptInput && attemptInput.value ? String(attemptInput.value) : '';
        if (!attemptid) {
            return null;
        }
        return quizid + '|' + attemptid;
    }

    function syncIndexedDBToAttemptOwner() {
        if (!db) {
            return;
        }
        const key = getAudioAttemptOwnerKey();
        if (key === null) {
            return;
        }
        const stored = localStorage.getItem(INDEXEDDB_OWNER_KEY);
        if (stored === key) {
            return;
        }
        if (stored === null || stored === '') {
            localStorage.setItem(INDEXEDDB_OWNER_KEY, key);
            return;
        }
        const transaction = db.transaction([storeName], 'readwrite');
        transaction.objectStore(storeName).clear();
        transaction.oncomplete = function () {
            localStorage.setItem(INDEXEDDB_OWNER_KEY, key);
            console.log('IndexedDB cleared — quiz attempt changed');
        };
    }

    function filterChunksForCurrentAttempt(chunks) {
        const key = getAudioAttemptOwnerKey();
        if (!key) {
            return chunks;
        }
        return chunks.filter(function (c) {
            return c && c.ownerKey === key;
        });
    }

    function openDB() {
        const request = indexedDB.open(dbName, 1);
        request.onupgradeneeded = function (e) {
            db = e.target.result;
            if (!db.objectStoreNames.contains(storeName)) {
                db.createObjectStore(storeName, { autoIncrement: true });
            }
        };
        request.onsuccess = function (e) {
            db = e.target.result;
            console.log('IndexedDB initialized');
            syncIndexedDBToAttemptOwner();

            const isReviewOrSummaryPage = window.location.href.includes('/review.php') ||
                window.location.href.includes('/summary.php');
            if (isReviewOrSummaryPage) {
                checkAndUploadChunks(true);
            }
        };
        request.onerror = function (e) {
            console.error("IndexedDB error:", e.target.errorCode);
        };
    }
    openDB();

    function useraudiorecord(stream) {
        console.log('Audio monitoring started');
        syncIndexedDBToAttemptOwner();
        audioContext = new (window.AudioContext || window.webkitAudioContext)();
        analyser = audioContext.createAnalyser();
        source = audioContext.createMediaStreamSource(stream);
        source.connect(analyser);
        analyser.fftSize = 2048;
        analyser.smoothingTimeConstant = 0.8;

        const bufferLength = analyser.frequencyBinCount;
        const frequencyDataArray = new Uint8Array(bufferLength);
        const timeDomainDataArray = new Float32Array(analyser.fftSize);

        function computeRms(samples) {
            let energy = 0;
            for (let i = 0; i < samples.length; i++) {
                energy += samples[i] * samples[i];
            }
            return Math.sqrt(energy / samples.length);
        }

        function computeZeroCrossingRate(samples) {
            let crossings = 0;
            for (let i = 1; i < samples.length; i++) {
                if ((samples[i - 1] >= 0 && samples[i] < 0) || (samples[i - 1] < 0 && samples[i] >= 0)) {
                    crossings++;
                }
            }
            return crossings / samples.length;
        }

        function computeCrestFactor(samples) {
            let peak = 0;
            let sumSq = 0;
            for (let i = 0; i < samples.length; i++) {
                const a = Math.abs(samples[i]);
                if (a > peak) {
                    peak = a;
                }
                sumSq += samples[i] * samples[i];
            }
            const rms = Math.sqrt(sumSq / samples.length);
            return rms > 1e-9 ? peak / rms : 0;
        }

        function getEnergyFractionAboveHz(freqData, sampleRate, aboveHz) {
            const nyquist = sampleRate / 2;
            const hzPerBin = nyquist / freqData.length;
            let highEnergy = 0;
            let total = 0;
            for (let i = 0; i < freqData.length; i++) {
                const hz = i * hzPerBin;
                const v = freqData[i];
                total += v;
                if (hz >= aboveHz) {
                    highEnergy += v;
                }
            }
            return total > 0 ? highEnergy / total : 0;
        }

        function getSpeechBandPeakiness(freqData, sampleRate) {
            const nyquist = sampleRate / 2;
            const hzPerBin = nyquist / freqData.length;
            let maxVal = 0;
            let sum = 0;
            let n = 0;
            for (let i = 0; i < freqData.length; i++) {
                const hz = i * hzPerBin;
                if (hz >= vadConfig.speechBandMinHz && hz <= vadConfig.speechBandMaxHz) {
                    const v = freqData[i];
                    if (v > maxVal) {
                        maxVal = v;
                    }
                    sum += v;
                    n++;
                }
            }
            if (n === 0) {
                return 0;
            }
            const mean = sum / n;
            return mean > 0 ? maxVal / mean : 0;
        }

        function getSpeechBandRatio(freqData, sampleRate) {
            const nyquist = sampleRate / 2;
            const hzPerBin = nyquist / freqData.length;
            let speechBandEnergy = 0;
            let fullBandEnergy = 0;

            for (let i = 0; i < freqData.length; i++) {
                const hz = i * hzPerBin;
                const value = freqData[i];
                fullBandEnergy += value;
                if (hz >= vadConfig.speechBandMinHz && hz <= vadConfig.speechBandMaxHz) {
                    speechBandEnergy += value;
                }
            }
            if (fullBandEnergy === 0) {
                return 0;
            }
            return speechBandEnergy / fullBandEnergy;
        }

        function getLowBandEnergyRatio(freqData, sampleRate, minHz, maxHz) {
            const nyquist = sampleRate / 2;
            const hzPerBin = nyquist / freqData.length;
            let bandEnergy = 0;
            let fullBandEnergy = 0;
            for (let i = 0; i < freqData.length; i++) {
                const hz = i * hzPerBin;
                const value = freqData[i];
                fullBandEnergy += value;
                if (hz >= minHz && hz <= maxHz) {
                    bandEnergy += value;
                }
            }
            if (fullBandEnergy === 0) {
                return 0;
            }
            return bandEnergy / fullBandEnergy;
        }

        function detectHighPitchPeriodicTone(samples, sampleRate) {
            const minLag = Math.max(2, Math.floor(sampleRate / vadConfig.highPitchDetectMaxHz));
            const maxLag = Math.floor(sampleRate / vadConfig.highPitchDetectMinHz);
            let bestCorrelation = 0;
            for (let lag = minLag; lag <= maxLag; lag++) {
                let corr = 0;
                let energyA = 0;
                let energyB = 0;
                const length = samples.length - lag;
                for (let i = 0; i < length; i++) {
                    const a = samples[i];
                    const b = samples[i + lag];
                    corr += a * b;
                    energyA += a * a;
                    energyB += b * b;
                }
                const denom = Math.sqrt(energyA * energyB);
                if (denom > 0) {
                    const normalizedCorr = corr / denom;
                    if (normalizedCorr > bestCorrelation) {
                        bestCorrelation = normalizedCorr;
                    }
                }
            }
            return bestCorrelation >= vadConfig.highPitchCorrelationThreshold;
        }

        function detectVoicedPitch(samples, sampleRate) {
            const minLag = Math.floor(sampleRate / vadConfig.pitchMaxHz);
            const maxLag = Math.floor(sampleRate / vadConfig.pitchMinHz);
            let bestLag = -1;
            let bestCorrelation = 0;

            for (let lag = minLag; lag <= maxLag; lag++) {
                let corr = 0;
                let energyA = 0;
                let energyB = 0;
                const length = samples.length - lag;

                for (let i = 0; i < length; i++) {
                    const a = samples[i];
                    const b = samples[i + lag];
                    corr += a * b;
                    energyA += a * a;
                    energyB += b * b;
                }

                const denom = Math.sqrt(energyA * energyB);
                if (denom > 0) {
                    const normalizedCorr = corr / denom;
                    if (normalizedCorr > bestCorrelation) {
                        bestCorrelation = normalizedCorr;
                        bestLag = lag;
                    }
                }
            }

            if (bestLag <= 0) {
                return { isVoiced: false };
            }

            const pitchHz = sampleRate / bestLag;
            return {
                isVoiced: bestCorrelation >= vadConfig.voicedCorrelationThreshold &&
                    pitchHz >= vadConfig.pitchMinHz &&
                    pitchHz <= vadConfig.pitchMaxHz
            };
        }

        function isSpeechLikeFrame() {
            analyser.getFloatTimeDomainData(timeDomainDataArray);
            analyser.getByteFrequencyData(frequencyDataArray);

            const rmsEnergy = computeRms(timeDomainDataArray);
            const zeroCrossingRate = computeZeroCrossingRate(timeDomainDataArray);
            const speechBandRatio = getSpeechBandRatio(frequencyDataArray, audioContext.sampleRate);
            const lowBandRatio = getLowBandEnergyRatio(
                frequencyDataArray,
                audioContext.sampleRate,
                vadConfig.unvoicedLowBandMinHz,
                vadConfig.unvoicedLowBandMaxHz
            );
            const voicedInfo = detectVoicedPitch(timeDomainDataArray, audioContext.sampleRate);
            const isHighPitchPeriodicTone = detectHighPitchPeriodicTone(timeDomainDataArray, audioContext.sampleRate);
            const crestFactor = computeCrestFactor(timeDomainDataArray);
            const highFreqEnergyRatio = getEnergyFractionAboveHz(
                frequencyDataArray,
                audioContext.sampleRate,
                vadConfig.highFreqCutoffHz
            );
            const speechBandPeakiness = getSpeechBandPeakiness(frequencyDataArray, audioContext.sampleRate);
            const dynamicEnergyThreshold = Math.max(
                vadConfig.minRmsEnergy,
                adaptiveNoiseFloor * vadConfig.energyThresholdRatio
            );

            if (vadCalibrating) {
                adaptiveNoiseFloor =
                    (adaptiveNoiseFloor * vadConfig.noiseFloorSmoothing) +
                    (rmsEnergy * (1 - vadConfig.noiseFloorSmoothing));
                vadCalibrationFrames++;
                if (vadCalibrationFrames >= vadConfig.calibrationFrameCount) {
                    vadCalibrating = false;
                    console.log('Audio baseline calibrated');
                }
                return false;
            }

            const energyScore = Math.max(0, Math.min(1, rmsEnergy / (dynamicEnergyThreshold * 1.8)));
            const bandScore = Math.max(0, Math.min(1, speechBandRatio / vadConfig.speechBandRatioThreshold));
            const zcrInRange =
                zeroCrossingRate >= vadConfig.minZeroCrossingRate &&
                zeroCrossingRate <= vadConfig.maxZeroCrossingRate;
            const zcrScore = zcrInRange ? 1 : 0.35;
            const voicedScore = voicedInfo.isVoiced ? 1 : 0.2;
            const frameSpeechScore = (energyScore * 0.35) + (bandScore * 0.3) + (zcrScore * 0.1) + (voicedScore * 0.25);
            const hasEnoughEnergyForStart = rmsEnergy >= Math.max(vadConfig.minStartRmsEnergy, dynamicEnergyThreshold * 1.15);
            const hasUnvoicedSpeechSignature =
                !isHighPitchPeriodicTone &&
                speechBandRatio >= (vadConfig.speechBandRatioThreshold + vadConfig.unvoicedSpeechBandBoost) &&
                zcrInRange &&
                energyScore >= 0.58 &&
                lowBandRatio >= vadConfig.minLowBandRatioForUnvoiced &&
                crestFactor <= vadConfig.maxCrestFactorForUnvoiced &&
                highFreqEnergyRatio <= vadConfig.maxHighFreqEnergyRatioForUnvoiced &&
                speechBandPeakiness <= vadConfig.maxSpeechBandPeakinessForUnvoiced;
            const hasVoiceSignature = voicedInfo.isVoiced || hasUnvoicedSpeechSignature;
            const crestTransient =
                !recordingStarted &&
                !voicedInfo.isVoiced &&
                crestFactor >= vadConfig.transientMinCrestFactor &&
                rmsEnergy >= dynamicEnergyThreshold * 1.25;
            const isTransientImpulse =
                !recordingStarted &&
                !voicedInfo.isVoiced &&
                (
                    crestTransient ||
                    (
                        rmsEnergy >= (dynamicEnergyThreshold * vadConfig.transientEnergySpikeRatio) &&
                        speechBandRatio <= vadConfig.transientMaxSpeechBandRatio &&
                        zeroCrossingRate >= vadConfig.transientMinZeroCrossingRate
                    )
                );

            if (isTransientImpulse) {
                transientSuppressionFramesLeft = vadConfig.transientSuppressionFrames;
                speechConfidence = Math.max(0, speechConfidence - (vadConfig.confidenceFall * 2));
                adaptiveNoiseFloor =
                    (adaptiveNoiseFloor * vadConfig.noiseFloorSmoothing) +
                    (rmsEnergy * (1 - vadConfig.noiseFloorSmoothing));
                return false;
            }

            if (!recordingStarted && transientSuppressionFramesLeft > 0) {
                transientSuppressionFramesLeft--;
                speechConfidence = Math.max(0, speechConfidence - vadConfig.confidenceFall);
                return false;
            }

            if (frameSpeechScore >= vadConfig.speechConfidenceKeepThreshold && hasVoiceSignature) {
                speechConfidence = Math.min(1, speechConfidence + vadConfig.confidenceRise);
            } else {
                speechConfidence = Math.max(0, speechConfidence - vadConfig.confidenceFall);
            }

            const looksLikeSpeech = recordingStarted
                ? speechConfidence >= vadConfig.speechConfidenceKeepThreshold
                : speechConfidence >= vadConfig.speechConfidenceStartThreshold && hasEnoughEnergyForStart && hasVoiceSignature;

            if (!looksLikeSpeech) {
                adaptiveNoiseFloor =
                    (adaptiveNoiseFloor * vadConfig.noiseFloorSmoothing) +
                    (rmsEnergy * (1 - vadConfig.noiseFloorSmoothing));
            }
            return looksLikeSpeech;
        }

        function detectAudioActivity() {
            if (isSpeechLikeFrame()) {
                speechFrameCount++;
                nonSpeechFrameCount = 0;

                if (!recordingStarted && speechFrameCount >= vadConfig.minSpeechFramesToStart) {
                    console.log('Speech detected — starting recording');
                    startRecording(stream);
                }
                if (recordingStarted && silenceTimer) {
                    clearTimeout(silenceTimer);
                    silenceTimer = null;
                }
            } else {
                nonSpeechFrameCount++;
                speechFrameCount = 0;

                if (recordingStarted && nonSpeechFrameCount >= vadConfig.nonSpeechFramesToStop && !silenceTimer) {
                    silenceTimer = setTimeout(() => {
                        console.log('No speech detected — stopping recording');
                        stopRecording();
                    }, 0);
                }
            }
        }

        setInterval(detectAudioActivity, vadConfig.frameIntervalMs);
    }

    function startRecording(stream) {
        const audioTracks = stream.getAudioTracks();
        const audioStream = new MediaStream(audioTracks);
        mediaRecorder = new MediaRecorder(audioStream);
        audioChunks = [];
        recordingSaved = false;
        recordingStarted = true;

        mediaRecorder.ondataavailable = function (e) {
            if (e.data.size > 0) {
                audioChunks.push({
                    blob: e.data,
                    timestamp: Math.floor(Date.now() / 1000)
                });
            }
        };

        mediaRecorder.onstop = function () {
            if (!recordingSaved) {
                for (const chunk of audioChunks) {
                    saveToIndexedDB(chunk.blob, chunk.timestamp);
                }
                recordingSaved = true;
                audioChunks = [];
            }
            recordingStarted = false;
            silenceTimer = null;
            clearTimeout(recordingMaxTimer);
        };

        mediaRecorder.start();

        recordingMaxTimer = setTimeout(() => {
            console.log('Max duration reached — stopping recording');
            stopRecording();
        }, 60000);
    }

    function stopRecording() {
        if (mediaRecorder && mediaRecorder.state === 'recording') {
            mediaRecorder.stop();
        }
    }

    function saveToIndexedDB(blob, timestamp) {
        syncIndexedDBToAttemptOwner();
        const ownerKey = getAudioAttemptOwnerKey() || '';
        const transaction = db.transaction([storeName], 'readwrite');
        const store = transaction.objectStore(storeName);
        store.add({ blob, timestamp, ownerKey });

        transaction.oncomplete = () => {
            console.log('Audio chunk with timestamp saved to IndexedDB');
            checkAndUploadChunks();
        };

        transaction.onerror = (e) => {
            console.error('IndexedDB error:', e.target.error);
        };
    }

    function checkAndUploadChunks(forceUpload = false, keepAlive = false) {
        if (!db || isUploading) {
            return Promise.resolve();
        }
        syncIndexedDBToAttemptOwner();
        return new Promise((resolve, reject) => {
            const transaction = db.transaction([storeName], 'readonly');
            const store = transaction.objectStore(storeName);
            const request = store.getAll();

            request.onsuccess = function () {
                const chunks = filterChunksForCurrentAttempt(request.result);
                if (chunks.length >= 5 || (forceUpload && chunks.length > 0)) {
                    console.log(`Uploading ${chunks.length} chunks from IndexedDB`);
                    uploadMultipleBlobs(chunks, keepAlive)
                        .then(resolve)
                        .catch(reject);
                } else {
                    if (forceUpload && chunks.length === 0) {
                        console.log('No chunks to upload');
                    }
                    resolve();
                }
            };

            request.onerror = function() {
                reject(new Error('Failed to read from IndexedDB'));
            };
        });
    }

    function uploadMultipleBlobs(chunks, keepAlive = false) {
        if (isUploading || chunks.length === 0) return Promise.resolve();
        isUploading = true;
        
        const formData = new FormData();
        const attemptid = document.querySelector('input[name="attempt"]')?.value || '';
        const quizidRaw = localStorage.getItem('quizid');
        let quizid = quizidRaw;
        if (quizidRaw) {
            try {
                quizid = JSON.parse(quizidRaw);
            } catch (err) {
                quizid = quizidRaw;
            }
        }
        const timestamps = [];

        chunks.forEach((chunk, index) => {
            formData.append(`audio${index}`, chunk.blob, `audio${index}.webm`);
            timestamps.push(chunk.timestamp);
        });

        formData.append("attemptid", attemptid);
        formData.append("quizid", quizid);
        formData.append("timestamps", JSON.stringify(timestamps));

        const uploadUrl = M.cfg.wwwroot + '/mod/quiz/accessrule/quizproctoring/upload_audio.php';

        // Use fetch with keepalive for beforeunload events (keeps request alive during page unload)
        return fetch(uploadUrl, {
            method: 'POST',
            body: formData,
            keepalive: keepAlive // Keep request alive even if page unloads
        })
        .then(response => response.json())
        .then(result => {
            console.log('Uploaded chunks:', result);
            clearIndexedDB();
            isUploading = false;
            return result;
        })
        .catch(error => {
            console.error('Upload error:', error);
            isUploading = false;
            throw error;
        });
    }

    function clearIndexedDB() {
        const transaction = db.transaction([storeName], 'readwrite');
        const store = transaction.objectStore(storeName);
        store.clear();
        transaction.oncomplete = () => {
            console.log('IndexedDB cleared after upload');
        };
    }

    function handleImmediateUpload() {
        // Prevent multiple simultaneous calls
        if (isHandlingUpload) {
            console.log('Upload already in progress, skipping duplicate call...');
            return Promise.resolve();
        }
        
        isHandlingUpload = true;
        return new Promise((resolve) => {
            console.log('Navigation action detected — checking for chunks to upload');
            
            const finishUpload = () => {
                isHandlingUpload = false;
                resolve();
            };
            
            // Stop current recording if active
            if (mediaRecorder && mediaRecorder.state === 'recording') {
                mediaRecorder.onstop = function () {
                    if (!recordingSaved) {
                        // Save chunks to IndexedDB synchronously
                        const savePromises = [];
                        for (const chunk of audioChunks) {
                            savePromises.push(new Promise((saveResolve) => {
                                const transaction = db.transaction([storeName], 'readwrite');
                                const store = transaction.objectStore(storeName);
                                const ownerKey = getAudioAttemptOwnerKey() || '';
                                const addRequest = store.add({ blob: chunk.blob, timestamp: chunk.timestamp, ownerKey });
                                addRequest.onsuccess = () => saveResolve();
                                addRequest.onerror = () => saveResolve(); // Continue even on error
                            }));
                        }
                        
                        Promise.all(savePromises).then(() => {
                            recordingSaved = true;
                            audioChunks = [];
                            // Wait a bit for IndexedDB to fully commit, then upload
                            setTimeout(() => {
                                checkAndUploadChunks(true, false)
                                    .then(finishUpload)
                                    .catch(() => finishUpload()); // Resolve anyway to allow navigation
                            }, 200);
                        });
                    } else {
                        checkAndUploadChunks(true, false)
                            .then(finishUpload)
                            .catch(() => finishUpload()); // Resolve anyway to allow navigation
                    }
                };
                mediaRecorder.stop();
            } else {
                // No active recording, just upload existing chunks
                checkAndUploadChunks(true, false)
                    .then(finishUpload)
                    .catch(() => finishUpload()); // Resolve anyway to allow navigation
            }
        });
    }

    window.useraudiorecord = useraudiorecord;

    // Store clicked button for form submission
    let clickedSubmitButton = null;

    // Listen for button clicks first to capture which button was clicked
    document.addEventListener('click', function(e) {
        const target = e.target;
        // Check if it's a submit button in a quiz form
        if ((target.tagName === 'INPUT' && target.type === 'submit') || 
            (target.tagName === 'BUTTON' && (target.type === 'submit' || !target.type))) {
            const form = target.closest('form');
            if (form && (
                form.id === 'responseform' ||
                form.classList.contains('quizform') ||
                form.querySelector('input[name="next"]') ||
                form.querySelector('input[name="previous"]') ||
                form.querySelector('input[name="back"]') ||
                form.querySelector('input[name="finishattempt"]')
            )) {
                // Store the clicked button
                clickedSubmitButton = target;
            }
        }
    }, true);

    // Listen for form submissions (quiz navigation)
    document.addEventListener('submit', function(e) {
        const form = e.target;
        
        // Skip if already handling upload or if this is a programmatic submit
        if (isHandlingUpload || form.dataset.programmaticSubmit === 'true') {
            return;
        }
        
        // Check if it's a quiz navigation form
        if (form.tagName === 'FORM' && (
            form.querySelector('input[name="next"]') ||
            form.querySelector('input[name="previous"]') ||
            form.querySelector('input[name="back"]') ||
            form.querySelector('input[name="finishattempt"]') ||
            form.querySelector('button[name="next"]') ||
            form.querySelector('button[name="previous"]') ||
            form.querySelector('button[name="back"]') ||
            form.querySelector('button[name="finishattempt"]') ||
            form.id === 'responseform' ||
            form.classList.contains('quizform')
        )) {
            e.preventDefault();
            e.stopPropagation();
            e.stopImmediatePropagation();
            
            // Use the stored clicked button or try to find it
            const submitButton = clickedSubmitButton || e.submitter || 
                form.querySelector('input[type="submit"]:focus, button[type="submit"]:focus') ||
                form.querySelector('input[name="next"], input[name="previous"], input[name="back"], input[name="finishattempt"]') ||
                form.querySelector('button[name="next"], button[name="previous"], button[name="back"], button[name="finishattempt"]') ||
                form.querySelector('input[type="submit"], button[type="submit"]');
            
            // Store button info for later submission
            const buttonName = submitButton ? submitButton.name : '';
            const buttonValue = submitButton ? submitButton.value : '';
            
            // Clear the stored button
            clickedSubmitButton = null;
            
            // Disable button to prevent double-clicks (but don't change text)
            if (submitButton) {
                submitButton.disabled = true;
            }
            
            handleImmediateUpload().then(() => {
                // Re-enable button
                if (submitButton) {
                    submitButton.disabled = false;
                }
                // Mark as programmatic submit to prevent re-triggering
                form.dataset.programmaticSubmit = 'true';
                
                // Create a hidden input with the button's name/value to preserve the action
                if (buttonName) {
                    // Remove any existing hidden input with same name
                    const existing = form.querySelector(`input[type="hidden"][name="${buttonName}"]`);
                    if (existing) {
                        existing.remove();
                    }
                    
                    const hiddenInput = document.createElement('input');
                    hiddenInput.type = 'hidden';
                    hiddenInput.name = buttonName;
                    if (buttonValue) {
                        hiddenInput.value = buttonValue;
                    }
                    form.appendChild(hiddenInput);
                }
                
                // Submit the form after upload completes
                // Ensure hidden input is added and form is ready
                if (buttonName) {
                    // Double-check the hidden input exists
                    let hiddenInput = form.querySelector(`input[type="hidden"][name="${buttonName}"]`);
                    if (!hiddenInput) {
                        hiddenInput = document.createElement('input');
                        hiddenInput.type = 'hidden';
                        hiddenInput.name = buttonName;
                        if (buttonValue) {
                            hiddenInput.value = buttonValue;
                        }
                        form.appendChild(hiddenInput);
                    }
                }
                
                // Submit using the native form.submit() method
                // This bypasses the submit event, so our listener won't catch it
                setTimeout(() => {
                    HTMLFormElement.prototype.submit.call(form);
                }, 50);
            }).catch(() => {
                // Even if upload fails, allow navigation
                if (submitButton) {
                    submitButton.disabled = false;
                }
                form.dataset.programmaticSubmit = 'true';
                
                // Create a hidden input with the button's name/value to preserve the action
                if (buttonName) {
                    // Remove any existing hidden input with same name
                    const existing = form.querySelector(`input[type="hidden"][name="${buttonName}"]`);
                    if (existing) {
                        existing.remove();
                    }
                    
                    const hiddenInput = document.createElement('input');
                    hiddenInput.type = 'hidden';
                    hiddenInput.name = buttonName;
                    if (buttonValue) {
                        hiddenInput.value = buttonValue;
                    }
                    form.appendChild(hiddenInput);
                }
                
                // Ensure hidden input is added
                if (buttonName) {
                    let hiddenInput = form.querySelector(`input[type="hidden"][name="${buttonName}"]`);
                    if (!hiddenInput) {
                        hiddenInput = document.createElement('input');
                        hiddenInput.type = 'hidden';
                        hiddenInput.name = buttonName;
                        if (buttonValue) {
                            hiddenInput.value = buttonValue;
                        }
                        form.appendChild(hiddenInput);
                    }
                }
                
                setTimeout(() => {
                    HTMLFormElement.prototype.submit.call(form);
                }, 50);
            });
        }
    }, true); // Use capture phase to catch early

    // Listen for button clicks on navigation buttons (only for non-form buttons and links)
    document.addEventListener('click', function(e) {
        // Skip if already handling upload
        if (isHandlingUpload) {
            return;
        }
        
        const target = e.target;
        const buttonName = target.name || target.getAttribute('name') || '';
        const buttonValue = target.value || target.textContent || '';
        const buttonId = target.id || '';
        let isNavigationButton = false;
        
        // Check for navigation buttons that are NOT submit buttons (submit buttons will trigger form submit)
        if ((target.tagName === 'BUTTON' && target.type !== 'submit') || 
            (target.tagName === 'INPUT' && target.type !== 'submit')) {
            if (buttonName === 'next' || 
                buttonName === 'previous' || 
                buttonName === 'back' || 
                buttonName === 'finishattempt' ||
                buttonValue.toLowerCase().includes('next') ||
                buttonValue.toLowerCase().includes('previous') ||
                buttonValue.toLowerCase().includes('back') ||
                buttonValue.toLowerCase().includes('finish') ||
                buttonId.includes('next') ||
                buttonId.includes('previous') ||
                buttonId.includes('back') ||
                buttonId.includes('finish')) {
                isNavigationButton = true;
            }
        }
        
        // Check for links that might navigate
        if (target.tagName === 'A' && (
            target.href.includes('attempt.php') ||
            target.href.includes('summary.php') ||
            target.href.includes('review.php')
        )) {
            isNavigationButton = true;
        }
        
        if (isNavigationButton) {
            e.preventDefault();
            e.stopPropagation();
            e.stopImmediatePropagation();
            
            // Disable button during upload
            if (target.tagName === 'BUTTON' || target.tagName === 'INPUT') {
                target.disabled = true;
            }
            
            handleImmediateUpload().then(() => {
                // Re-enable and trigger navigation
                if (target.tagName === 'BUTTON' || target.tagName === 'INPUT') {
                    target.disabled = false;
                    // Use a small delay to ensure upload completes
                    setTimeout(() => {
                        target.click();
                    }, 50);
                } else if (target.tagName === 'A') {
                    window.location.href = target.href;
                }
            }).catch(() => {
                // Even if upload fails, allow navigation
                if (target.tagName === 'BUTTON' || target.tagName === 'INPUT') {
                    target.disabled = false;
                    setTimeout(() => {
                        target.click();
                    }, 50);
                } else if (target.tagName === 'A') {
                    window.location.href = target.href;
                }
            });
        }
    }, true); // Use capture phase

    // Listen for page reload - use sendBeacon for reliability
    window.addEventListener('beforeunload', function (e) {
        if (mediaRecorder && mediaRecorder.state === 'recording') {
            console.log('Page is refreshing — stopping current recording and saving...');
            mediaRecorder.onstop = function () {
                if (!recordingSaved) {
                    // Save chunks synchronously
                    const savePromises = [];
                    for (const chunk of audioChunks) {
                        savePromises.push(new Promise((saveResolve) => {
                            const transaction = db.transaction([storeName], 'readwrite');
                            const store = transaction.objectStore(storeName);
                            const ownerKey = getAudioAttemptOwnerKey() || '';
                            const addRequest = store.add({ blob: chunk.blob, timestamp: chunk.timestamp, ownerKey });
                            addRequest.onsuccess = () => saveResolve();
                            addRequest.onerror = () => saveResolve();
                        }));
                    }
                    
                    Promise.all(savePromises).then(() => {
                        recordingSaved = true;
                        audioChunks = [];
                        setTimeout(() => {
                            checkAndUploadChunks(true, true); // Use keepalive
                        }, 100);
                    });
                } else {
                    checkAndUploadChunks(true, true); // Use keepalive
                }
            };
            mediaRecorder.stop();
        } else {
            // Even if not recording, upload any existing chunks using keepalive
            checkAndUploadChunks(true, true); // Use keepalive
        }
    });
})();